// === FILTER ARTICLES WITH PDFS ===
// Garde seulement les articles ayant un pdf_local OU un pdf_url telechargeable
const items = $input.all();
const all = items.map(i => i.json);
const withPdf = all.filter(a => a.pdf_local && a.pdf_local.length > 0);
const extractFields = (all[0] && all[0].extract_fields) || [
  { name: 'population',   description: 'Population studied (age, gender, condition, sample size)' },
  { name: 'intervention', description: 'Intervention or exposure assessed' },
  { name: 'comparator',   description: 'Comparator or control group' },
  { name: 'outcomes',     description: 'Main outcomes measured (with values if available)' },
  { name: 'study_design', description: 'Study design (RCT, cohort, cross-sectional, etc.)' },
  { name: 'period',       description: 'Study period or follow-up duration' },
  { name: 'country',      description: 'Country/region where the study took place' },
  { name: 'main_findings',description: 'Key findings in 2-3 sentences' },
  { name: 'limitations',  description: 'Main limitations reported by the authors' }
];

console.log('PDF Extract: ' + all.length + ' articles total, ' + withPdf.length + ' avec PDF telecharge');
console.log('Champs a extraire: ' + extractFields.map(f => f.name).join(', '));

if (withPdf.length === 0) {
  return [{ json: { _error: 'Aucun PDF disponible. Lancez d\'abord le module pdf-fetch.', _articles: all } }];
}

// Propager extract_fields a tous les articles + index
return withPdf.map((a, i) => ({
  json: {
    ...a,
    _extract_fields: extractFields,
    _article_index: i,
    _total: withPdf.length
  }
}));

// === BUILD EXTRACTION PROMPT (runOnceForAllItems) ===
const pdfResponses = $input.all();
const articles = $('Filter & Prepare').all().map(i => i.json);

function sanitize(text) {
  return (text || '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim();
}

const out = [];
for (let i = 0; i < articles.length; i++) {
  const article = articles[i];
  const pdfResp = (pdfResponses[i] && pdfResponses[i].json) || {};
  const fields = article._extract_fields || [];

  const pdfText = pdfResp.text || '';
  const pdfFailed = !pdfResp.success || !pdfText;

  const title = sanitize(article.title || 'Untitled').substring(0, 200);
  const doi = article.doi || '';

  let sourceText = pdfText;
  let sourceType = 'PDF full text';
  if (pdfFailed) {
    sourceText = sanitize(article.abstract || '');
    sourceType = 'abstract only (PDF unavailable)';
    console.log('[' + (article._article_index !== undefined ? article._article_index : i) + '] PDF failed for: ' + title.substring(0, 60));
  }

  if (!sourceText) {
    out.push({ json: {
      prompt: 'NO_TEXT_AVAILABLE',
      _article: article,
      _source_type: 'none',
      _has_text: false
    }});
    continue;
  }

  const fieldList = fields.map(f => '- ' + f.name + ': ' + f.description).join('\n');
  const jsonExample = '{' + fields.map(f => '"' + f.name + '": "..."').join(', ') + '}';

  const prompt = 'You are a scientific data extraction assistant. Extract structured information from this research article.\n\nARTICLE:\nTitle: ' + title + '\nDOI: ' + doi + '\nSource: ' + sourceType + '\n\nFULL TEXT:\n' + sourceText.substring(0, 12000) + '\n\n=== FIELDS TO EXTRACT ===\n' + fieldList + '\n\n=== INSTRUCTIONS ===\n1. Extract each field by reading the article carefully.\n2. Use the EXACT phrases from the article when possible (do not paraphrase numbers/values).\n3. If a field cannot be determined from the text, return "not reported".\n4. Keep each value concise: maximum 200 characters.\n5. Return ONLY a JSON object with these exact keys, no markdown, no comments:\n' + jsonExample;

  out.push({ json: {
    prompt: prompt,
    _article: article,
    _source_type: sourceType,
    _has_text: true
  }});
}

console.log('Build Prompt: ' + out.length + ' prompts generated');
return out;

// === PARSE EXTRACTION RESULTS (runOnceForAllItems) ===
const llmResponses = $input.all();
const buildResults = $('Build Prompt').all().map(i => i.json);

function extractJson(text) {
  if (!text) return null;
  text = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '');
  const start = text.indexOf('{');
  if (start === -1) return null;
  let depth = 0, inString = false, escape = false;
  for (let i = start; i < text.length; i++) {
    const c = text[i];
    if (escape) { escape = false; continue; }
    if (c === '\\') { escape = true; continue; }
    if (c === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (c === '{') depth++;
    else if (c === '}') {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(text.substring(start, i + 1)); } catch(e) { return null; }
      }
    }
  }
  return null;
}

const out = [];
let okCount = 0;
for (let i = 0; i < buildResults.length; i++) {
  const buildItem = buildResults[i];
  const article = buildItem._article;
  const sourceType = buildItem._source_type;
  const hasText = buildItem._has_text;

  // Si pas de texte, on retourne directement (pas d'appel LLM)
  if (!hasText) {
    out.push({ json: { ...article, _extracted: {}, _extract_status: 'no_text_available', _extract_source: 'none' }});
    continue;
  }

  const llmResp = (llmResponses[i] && llmResponses[i].json) || {};
  let extracted = {};
  let status = 'failed';

  // Sauvegarder un echantillon de reponses brutes pour diagnostic (5 premiers articles).
  // Capture aussi le message d'erreur quand response est undefined (cas llm_error) :
  // sans ca on ne sait pas si Ollama timeout, OOM, modele decharge, etc.
  if (i < 5) {
    if (llmResp.response !== undefined) {
      article._debug_llm_raw = String(llmResp.response).substring(0, 500);
    } else if (llmResp.error !== undefined) {
      const errStr = typeof llmResp.error === 'string' ? llmResp.error : JSON.stringify(llmResp.error);
      article._debug_llm_raw = '[ERROR] ' + errStr.substring(0, 500);
    }
    article._debug_llm_keys = Object.keys(llmResp).slice(0, 10);
  }
  if (llmResp.response) {
    const parsed = extractJson(llmResp.response);
    if (parsed && typeof parsed === 'object') {
      extracted = parsed;
      status = 'ok';
      okCount++;
    } else {
      status = 'parse_error';
    }
  } else if (llmResp.error) {
    status = 'llm_error';
    if (i < 3) console.log('LLM error article ' + i + ': ' + JSON.stringify(llmResp.error).substring(0, 300));
  } else if (llmResp.response === undefined) {
    status = 'no_response';
    if (i < 3) console.log('No response field article ' + i + ': ' + JSON.stringify(llmResp).substring(0, 300));
  }

  out.push({ json: { ...article, _extracted: extracted, _extract_status: status, _extract_source: sourceType }});
}

console.log('Parse Extraction: ' + okCount + '/' + out.length + ' extractions OK');
return out;

// === LOG SUMMARY ===
const items = $input.all();
const articles = items.map(i => i.json);
const ok = articles.filter(a => a._extract_status === 'ok').length;
const parseErr = articles.filter(a => a._extract_status === 'parse_error').length;
const llmErr = articles.filter(a => a._extract_status === 'llm_error').length;
const noText = articles.filter(a => a._extract_status === 'no_text_available').length;
const failed = articles.length - ok;
console.log('=== PDF Extract complete ===');
console.log('Articles traites : ' + articles.length);
console.log('  OK              : ' + ok);
console.log('  Erreurs parse   : ' + parseErr);
console.log('  Erreurs LLM     : ' + llmErr);
console.log('  Sans texte      : ' + noText);
if (failed === articles.length) {
  console.log('!!! AUCUN article extrait avec succes - verifier que :');
  console.log('  1. Les PDFs sont bien presents (champ pdf_local rempli)');
  console.log('  2. Le proxy /extract-pdf fonctionne (logs proxy)');
  console.log('  3. Le LLM repond bien (logs proxy /api/generate)');
  // Logger le 1er article en detail pour debug
  const a = articles[0] || {};
  console.log('  Article 0 :');
  console.log('    pdf_local : ' + (a.pdf_local || '(vide)'));
  console.log('    status    : ' + a._extract_status);
  console.log('    source    : ' + a._extract_source);
  console.log('    extracted : ' + JSON.stringify(a._extracted || {}));
}
return articles.map(a => ({ json: a }));
